import React, { useState } from "react";

export default function ReportForm({ location, onSubmit, onCancel, loading }) {
  const [title, setTitle] = useState("");
  const [severity, setSeverity] = useState("Medium");
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState("");

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result);
      setImageFile(reader.result);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!title.trim()) return;
    onSubmit({ title: title.trim(), severity, image: imageFile || "" });
  };

  return (
    <div style={{
      position: "fixed",
      inset: 0,
      background: "rgba(0,0,0,0.5)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      zIndex: 9999,
      padding: 16
    }}>
      <div style={{
        background: "#fff",
        borderRadius: 14,
        padding: 28,
        width: "100%",
        maxWidth: 420,
        boxShadow: "0 20px 60px rgba(0,0,0,0.25)",
        fontFamily: "sans-serif"
      }}>
        <h3 style={{ margin: "0 0 6px", fontSize: 18, fontWeight: 700, color: "#2c3e50" }}>
          Report a Waste Spot
        </h3>
        <p style={{ margin: "0 0 20px", fontSize: 13, color: "#888" }}>
          📍 {location.lat.toFixed(5)}, {location.lng.toFixed(5)}
        </p>

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: 16 }}>
            <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#444", marginBottom: 6 }}>
              Title *
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Describe the waste issue..."
              required
              style={{
                width: "100%",
                padding: "10px 12px",
                border: "1.5px solid #ddd",
                borderRadius: 8,
                fontSize: 14,
                outline: "none",
                boxSizing: "border-box",
                fontFamily: "sans-serif"
              }}
              onFocus={(e) => { e.target.style.borderColor = "#3498db"; }}
              onBlur={(e) => { e.target.style.borderColor = "#ddd"; }}
            />
          </div>

          <div style={{ marginBottom: 16 }}>
            <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#444", marginBottom: 6 }}>
              Severity
            </label>
            <select
              value={severity}
              onChange={(e) => setSeverity(e.target.value)}
              style={{
                width: "100%",
                padding: "10px 12px",
                border: "1.5px solid #ddd",
                borderRadius: 8,
                fontSize: 14,
                background: "#fff",
                cursor: "pointer",
                fontFamily: "sans-serif"
              }}
            >
              <option value="Low">🟢 Low — Minor littering</option>
              <option value="Medium">🟡 Medium — Significant dump</option>
              <option value="High">🔴 High — Hazardous / Urgent</option>
            </select>
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#444", marginBottom: 6 }}>
              Photo (optional)
            </label>
            <input
              type="file"
              accept="image/*"
              onChange={handleImageChange}
              style={{ fontSize: 13, color: "#666", width: "100%", boxSizing: "border-box" }}
            />
            {imagePreview && (
              <img
                src={imagePreview}
                alt="preview"
                style={{ marginTop: 10, width: "100%", maxHeight: 140, objectFit: "cover", borderRadius: 8, border: "1px solid #eee" }}
              />
            )}
          </div>

          <div style={{ display: "flex", gap: 10 }}>
            <button
              type="button"
              onClick={onCancel}
              style={{
                flex: 1,
                padding: "11px",
                background: "#f5f5f5",
                color: "#444",
                border: "none",
                borderRadius: 8,
                fontSize: 14,
                fontWeight: 600,
                cursor: "pointer"
              }}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              style={{
                flex: 2,
                padding: "11px",
                background: loading ? "#aaa" : "#e74c3c",
                color: "white",
                border: "none",
                borderRadius: 8,
                fontSize: 14,
                fontWeight: 700,
                cursor: loading ? "not-allowed" : "pointer"
              }}
            >
              {loading ? "Saving..." : "Submit Report"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
